<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full  d-flex">
                    <h4 class="modal-title">{{ $t('SetDates') }}</h4>
                    <span class="user-guide">
                        <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG" role="button" aria-expanded="false" aria-controls="collapseExample"> <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                        <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                            <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                <div class="con" v-html="$t('RateScheduleCopy')"></div>
                            </div>
                        </div>
                    </span>
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>
                <div class="modal-body">
                    <dynamic-form lang="en" ref="ResourceRate" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataService from '../../services/DataService';
export default {
    props: {
        EditData: {
            type: Array,
            required: false,
        },
    },
    data() {
        return {
            isLoading: false,
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            companyId: null,
            userId: null,
            PageSize: 100,
            PageNumber: 1,
            searchCondition: '',
            GroupNewData: [],
            UtiltityNames: [],
            StateNames: [],
            WorkCodes: [],
            StatusData: [],
            FormSchema: [{
                    layoutType: "double",
                    Data: [                        
                        {
                            astype: "DateField",
                            label: this.$t('Start Date (M/D/YYYY)'),
                            name: "StartDate",
                            value: new Date(),
                            visibility: true,
                            placeholder: this.$t('StartDate'),
                            config: {
                                format: "MM/DD/YYYY",
                                onChange: this.onStartDateChange
                            },
                            validationRules: {
                                "required": true
                            },
                            visibility: true,
                            disabled: false,
                        },                        
                        {
                            astype: "DateField",
                            label: this.$t('End Date (M/D/YYYY)'),
                            name: "EndDate",
                            value: '',
                            visibility: true,
                            placeholder: this.$t('EndDate'),
                            config: {
                                format: "MM/DD/YYYY"
                            },
                            validationRules: {
                                "required": true
                            },
                            visibility: true,
                            disabled: false,
                        }, 
                        {
                            astype: "RadioField",
                            label: '',
                            name: "PreviousRecords",
                            visibility: true,
                            disabled: false,
                            value: true,
                            config: {
                                options: [{ value: 1, name: `${this.$t('previous records End Date will be updated as:')} ${
                                new Date(new Date().setDate(new Date().getDate() - 1)).toLocaleDateString()}` }],
                                onChange: this.PreviousRecords
                            }
                        },
                        {
                            astype: "RadioField",
                            label: '',
                            name: "RecordsInactive",
                            visibility: true,
                            disabled: false,
                            value: false,
                            config: {
                                options: [{ value: 2, name: this.$t('Do you want to mark previous Records as Inactive?') }],
                                onChange: this.RecordsInactive
                            }
                        },                       

                    ]
                },
                {
                    layoutType: "single",
                    Data: [{
                        astype: "TextAreaField",
                        label: this.$t('Comment'),
                        name: "Comment",
                        value: "",
                        placeholder: this.$t('Enter Comment'),
                        validationRules: {
                            //"required": false
                        }
                    }]
                }

            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Set New Dates",
                    isVisible: true,
                },                
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        if(vm.EditData[0].RATE_SCHEDULE_ID>0){ 
            debugger;           
            // (vm.FormSchema)[0].Data[1].value=vm.EditData[0].AMOUNT;            
            // (vm.FormSchema)[0].Data[3].value=vm.$options.filters.formatDate(vm.EditData[0].END_DATE)
        }
    },
    methods: { 
        PreviousRecords() {
            if(this.FormSchema[0].Data[2].value=='1'){
                this.FormSchema[0].Data[3].value=false;
            }else{
                this.FormSchema[0].Data[3].value=true;
            }           
        },
        RecordsInactive() {        
            if(this.FormSchema[0].Data[3].value=='2'){
                this.FormSchema[0].Data[2].value=false;
            }else{
                this.FormSchema[0].Data[2].value=true;
            } 
        },

    //    onSubmit(formfields, val) {
    //         const vm = this;
    //         debugger

    //         const result = vm.$refs.ResourceRate.validateForm.validate();
    //         if (!result) return;

    //         const objData = {
    //             // MUST be comma-separated string
    //             RateScheduleId: vm.EditData
    //                 .filter(x => x.isSelected)
    //                 .map(x => x.RATE_SCHEDULE_ID)
    //                 .join(","),

    //             ClientId: vm.EditData.length > 0 ? vm.EditData[0].CLIENT_ID : null,

    //             // API expects string → decimal
    //             Rate: vm.EditData.length > 0
    //                 ? vm.EditData[0].AMOUNT.toString()
    //                 : "0",

    //             // Always send ISO date to backend
    //             EndDate: formfields.EndDate
    //                 ? new Date(formfields.EndDate).toISOString()
    //                 : null,

    //             Comment: formfields.Comment || ""
    //         };

    //         DataService.BulkUpdateRate(objData).then(response => {
    //             if (!response.data) return;

    //             const Result = JSON.parse(response.data)[0];

    //             if (parseInt(Result.RESULT) === 1) {
    //                 vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('RateSchedule')]),"success",true,vm.$t("Alert"));
    //                 vm.Close();
    //             } else {
    //                 vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
    //             }
    //         });
    //     },
     onStartDateChange(value) {
            this.updatePreviousRecordText(value);
        },
      updatePreviousRecordText(startDate) {
    const prevDate = this.getPreviousDate(startDate);
    
    // Direct access by index (more reliable)
    if (this.FormSchema[0].Data[2] && 
        this.FormSchema[0].Data[2].config && 
        this.FormSchema[0].Data[2].config.options) {
        
        this.FormSchema[0].Data[2].config.options[0].name =
            `${this.$t('previous records End Date will be updated as:')} ${prevDate}`;
    }
},
           getPreviousDate(date) {
            const d = new Date(date);
            d.setDate(d.getDate() - 1);
            return d.toLocaleDateString();
        },
onSubmit(formfields, val) {
    const vm = this;
    debugger

    // Date validation: Start Date should not be greater than End Date
    if (formfields.StartDate && formfields.EndDate) {
        const startDate = new Date(formfields.StartDate);
        const endDate = new Date(formfields.EndDate);
        
        if (startDate > endDate) {
            vm.ShowAlert(
                "Start Date should be less than End Date.",
                "warning",
                true,
                "Validation Error"
            );
            return; // Stop submission
        }
    }

    const result = vm.$refs.ResourceRate.validateForm.validate();
    if (!result) return;

    const objData = {
        // MUST be comma-separated string
        RateScheduleId: vm.EditData
            .filter(x => x.isSelected)
            .map(x => x.RATE_SCHEDULE_ID)
            .join(","),

        ClientId: vm.EditData.length > 0 ? vm.EditData[0].CLIENT_ID : null,

        // API expects string → decimal
        Rate: vm.EditData.length > 0
            ? vm.EditData[0].AMOUNT.toString()
            : "0",

        // Always send ISO date to backend
        StartDate: formfields.StartDate
            ? new Date(formfields.StartDate).toISOString()
            : null,
            
        EndDate: formfields.EndDate
            ? new Date(formfields.EndDate).toISOString()
            : null,

        Comment: formfields.Comment || ""
    };

    DataService.BulkUpdateRate(objData).then(response => {
        if (!response.data) return;

        const Result = JSON.parse(response.data)[0];

        if (parseInt(Result.RESULT) === 1) {
            vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('RateSchedule')]),"success",true,vm.$t("Alert"));
            vm.Close();
        } else {
            vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
        }
    });
},
        Close: function () {
            this.$parent.FetchData();
            this.$parent.isCopyRate = false;
        }
    }
}
</script>
